import { DEFAULT_BRUSH_SETTINGS } from "@/components/BrushSettingsPanel";
import type { BrushSettings } from "@/components/BrushSettingsPanel";

// Generates a soft radial gradient tip image (black center → white edge).
// Used as the airbrush tip so the image-based luminance path in the shader
// produces a natural powdery falloff without any special-case Gaussian code.
function makeRadialGradientTip(size = 128): string {
  if (typeof document === "undefined") return "";
  const canvas = document.createElement("canvas");
  canvas.width = canvas.height = size;
  const ctx = canvas.getContext("2d");
  if (!ctx) return "";
  const c = size / 2;
  const grd = ctx.createRadialGradient(c, c, 0, c, c, c);
  grd.addColorStop(0, "rgb(0,0,0)");
  grd.addColorStop(1, "rgb(255,255,255)");
  ctx.fillStyle = grd;
  ctx.fillRect(0, 0, size, size);
  return canvas.toDataURL("image/png");
}

const AIRBRUSH_TIP_DATA_URL = makeRadialGradientTip();

