export async function loadDefaultPresets(): Promise<typeof DEFAULT_PRESETS> {
  try {
    const res = await fetch(
      "/assets/brushes_1-019d5727-2810-7365-adc8-6dab5b5a6daf.hbrush",
    );
    if (!res.ok) return DEFAULT_PRESETS;
    const b64 = await res.text();
    const json = JSON.parse(atob(b64));
    if (json?.presets) {
      // Migrate legacy 'smear' key to 'smudge' (renamed in a prior update).
      // .hbrush files exported before the rename will have { smear: [...] }
      // instead of { smudge: [...] }. Remap so the rest of the app never sees 'smear'.
      const raw = json.presets as Record<string, unknown>;
      if (raw.smear && !raw.smudge) {
        raw.smudge = raw.smear;
        raw.smear = undefined;
      }
      // Guard: ensure every expected key is a non-empty array.
      for (const key of ["brush", "smudge", "eraser"] as const) {
        if (!Array.isArray(raw[key]) || (raw[key] as unknown[]).length === 0) {
          raw[key] = DEFAULT_PRESETS[key];
        }
      }
      return raw as unknown as typeof DEFAULT_PRESETS;
    }
    return DEFAULT_PRESETS;
  } catch {
    return DEFAULT_PRESETS;
  }
}
